mapper.select:
select Class_ID as classId, Class_Name as className, Class_Major as classMajor, Class_Grade as classGrade, Class_Num as classNum, Class_Department as classDepartment from class
and Class_Grade = #{classGrade}
and Class_Department like concat('%', #{classDepartment}, '%')
and Class_Major like concat('%', #{classMajor}, '%')
order by Class_ID limit #{offset}, #{pageSize}

select count(*)
from class


        and Class_Grade = #{classGrade}


        and Class_Department = #{classDepartment}


        and Class_Major like concat('%', #{classMajor}, '%')
